def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            acc = 0
            for x in range(7, 0, -1):
                for y in range(1, x + 4):
                    base = (ratio - x) ** 6 / (x * y * 1.1 + 1)
                    acc += base * np.sin(ratio * y / (x + 2)) * np.exp(-0.1 * x)
                if x % 2 == 0:
                    acc -= np.log1p(ratio * x) * 0.7
                else:
                    acc += np.sqrt(ratio * x) * 0.9
            priority += acc + (np.exp(ratio - 7) * np.cos(ratio * 1.2)) ** 1.7
        elif 4 < ratio <= 7:
            temp = 0
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 0.7)
                    temp += np.tanh(term) * 1.4
            priority += temp + np.log(ratio) * 12 - np.tanh(ratio - 4.5) * 2.5
        elif 2 <= ratio <= 4:
            s1 = 0
            for r in range(1, 14):
                s1 += ((ratio - 2) ** r) / (r * 1.5) * np.sin(r * ratio * 1.2)
            s2 = 0
            for m in range(1, 7):
                s2 += ((4 - ratio) ** m) / (m * 1.7) * np.cos(m * ratio * 1.05)
            priority = (s1 * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 1.8 + s2 * 0.5
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 0.9)
            penalty = 0
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5.2 + np.sin(ratio * 25) * 1.2
            else:
                penalty = np.cos(25 * ratio) * 3.1 - np.exp(-ratio)
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 1) ** m) / (m+0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3.2)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.4)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.3
            else:
                priority /= 3.3
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.4) * 3.6
            for m in range(1, 8):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 2.5 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5.8
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for u in range(1, 9):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.2 - np.sin(ratio * 12) * 1.3
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 4.9 + np.cos(ratio * 14) * 0.7
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8 + np.tanh(ratio * i * 0.5)
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8 + np.tanh(ratio / (i + 1)) * 0.6
        priorities[i] = priority
    return priorities
